// sumAbsoluteValues returns the sum of absolute values of non-zero elements in values.
func sumAbsoluteValues(values []int) int {
	var sum int
	for _, v := range values {
		if v > 0 {
			sum += v
		} else if v < 0 {
			sum -= v
		}
	}
	return sum
}

// formatNonZeroValues appends a comma-separated list of values to the builder.
func formatNonZeroValues(values []int, includeFormatting bool, b *strings.Builder) {
	for _, v := range values {
		if v == 0 { continue }
		if !includeFormatting { continue }
		if v > 0 { b.WriteString(fmt.Sprintf("%d,", v)) } else { b.WriteString(fmt.Sprintf("(%d),", v)) }
	}
}

// SumAbsoluteAndFormat computes the sum of absolute values and optionally a labeled list.
func SumAbsoluteAndFormat(values []int, label string, includeFormatted bool) (int, string, error) {
	sum := sumAbsoluteValues(values)
	if sum == 0 { return 0, "", fmt.Errorf("empty result for %s", label) }
	var formatted strings.Builder
	formatNonZeroValues(values, includeFormatted, &formatted)
	s := formatted.String()
	if label != "" { s = label + ": " + s }
	return sum, s, nil
}
